import { createContext, useEffect, useState, useContext } from "react";
import emailjs from '@emailjs/browser';

const AuthContext = createContext();

export default function AuthProvider({children}) {
	const [user, setUser] = useState(null);
	const [users, setUsers] = useState(()=>{
		const storedUsers = localStorage.getItem('users');
		return storedUsers ? JSON.parse(storedUsers) : [{mobile: '1234567890', email: 'test@example.com', userId: 'user1'}];
	});
	const [otpStore, setOtpStore] = useState({}); // Temporary store for OTPs
	const [emailOtpStore, setEmailOtpStore] = useState({}); // Temporary store for email OTPs

	useEffect(() => {
		localStorage.setItem('users', JSON.stringify(users))
	}, [users])

	const sendOTP = async (mobile) => {
		// Real SMS integration using Twilio REST API
		// WARNING: This exposes API keys in frontend - use backend for production
		const otp = Math.floor(100000 + Math.random() * 900000).toString();
		setOtpStore(prev => ({...prev, [mobile]: otp}));

		const accountSid = process.env.REACT_APP_TWILIO_ACCOUNT_SID;
		const authToken = process.env.REACT_APP_TWILIO_AUTH_TOKEN;
		const fromNumber = process.env.REACT_APP_TWILIO_PHONE_NUMBER;

		if (!accountSid || !authToken || !fromNumber) {
			console.log(`OTP for ${mobile}: ${otp}`); // Fallback to console if no keys
			return true;
		}

		try {
			const response = await fetch(`https://api.twilio.com/2010-04-01/Accounts/${accountSid}/Messages.json`, {
				method: 'POST',
				headers: {
					'Authorization': 'Basic ' + btoa(`${accountSid}:${authToken}`),
					'Content-Type': 'application/x-www-form-urlencoded',
				},
				body: new URLSearchParams({
					From: fromNumber,
					To: mobile,
					Body: `Your OTP is: ${otp}`,
				}),
			});

			if (response.ok) {
				console.log('SMS sent successfully');
			} else {
				console.error('Failed to send SMS:', await response.text());
			}
		} catch (error) {
			console.error('Error sending SMS:', error);
		}

		return true;
	}

	const sendEmailVerification = (email) => {
		// Real email integration using EmailJS
		const otp = Math.floor(100000 + Math.random() * 900000).toString();
		setEmailOtpStore(prev => ({...prev, [email]: otp}));

		// EmailJS configuration - replace with your service details
		const serviceId = process.env.REACT_APP_EMAILJS_SERVICE_ID;
		const templateId = process.env.REACT_APP_EMAILJS_TEMPLATE_ID;
		const publicKey = process.env.REACT_APP_EMAILJS_PUBLIC_KEY;

		const templateParams = {
			to_email: email,
			otp: otp,
		};

		emailjs.send(serviceId, templateId, templateParams, publicKey)
			.then((response) => {
				console.log('Email sent successfully!', response.status, response.text);
			}, (error) => {
				console.error('Failed to send email:', error);
			});

		return true;
	}

	const verifyOTP = (mobile, otp) => {
		return otpStore[mobile] === otp;
	}

	const verifyEmailOTP = (email, otp) => {
		return emailOtpStore[email] === otp;
	}

	const logIn = (mobile, otp) => {
		if (verifyOTP(mobile, otp)) {
			const found = users.find((u) => u.mobile === mobile);
			if (found) {
				setUser({mobile, userId: found.userId});
				setOtpStore(prev => {
					const newStore = {...prev};
					delete newStore[mobile];
					return newStore;
				});
				return true;
			}
		}
		return false;
	}

	const signUp = (mobile, otp, email) => {
		if (verifyOTP(mobile, otp)) {
			const exists = users.some((u) => u.mobile === mobile || u.email === email);
			if (exists) return {success: false, message: 'Mobile number or email already registered'};
			const userId = 'user' + Date.now(); // Generate unique user ID
			const newUser = {mobile, email, userId};
			setUsers((prev) => [...prev, newUser]);
			setUser({mobile, userId});
			setOtpStore(prev => {
				const newStore = {...prev};
				delete newStore[mobile];
				return newStore;
			});
			return {success: true, userId};
		}
		return {success: false, message: 'Invalid OTP'};
	}

	const logOut = () => setUser(null);

	return (
		<AuthContext.Provider value={{user, logIn, signUp, logOut, sendOTP, sendEmailVerification, verifyEmailOTP}}>
			{children}
		</AuthContext.Provider>
	)
}

export const useAuth = () => useContext(AuthContext);
